using System;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Aba "Upgrades" do Menu Secundário ("-") — <see cref="SecondaryMenuController"/>.
///
/// Lista todos os upgrades já desbloqueados (<see cref="PlayerProgress.HasUpgrade"/>),
/// agrupados por categoria se quiserdes:
///
/// - Upgrades <b>toggleable</b>: o jogador pode ligar/desligar livremente ("A").
///   Estado guardado em <see cref="PlayerProgress.enabledUpgradeIds"/>.
/// - Upgrades <b>permanentes</b> (toggleable == false): aparecem na lista mas
///   o toggle está desactivado ("Sempre Activo").
///
/// Montagem no Editor:
/// - "allUpgrades": todos os <see cref="UpgradeData"/> candidatos a aparecer
///   (a aba filtra automaticamente os ainda não desbloqueados).
/// - "rowPrefab": prefab com <see cref="UpgradeRowUI"/> + Button.
/// - "listContainer": Transform pai das linhas instanciadas.
/// - "detailRoot"/"detailNameText"/"detailDescriptionText"/"detailStatusText":
///   painel central com os detalhes do upgrade seleccionado.
/// - "emptyState": GameObject mostrado quando nenhum upgrade está desbloqueado.
/// </summary>
public class UpgradesTabUI : MonoBehaviour, ISecondaryMenuTab
{
    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Header("Lista de Upgrades")]
    [Tooltip("Todos os UpgradeData candidatos (desbloqueados ou não). A aba filtra os não desbloqueados.")]
    [SerializeField] private List<UpgradeData> allUpgrades = new List<UpgradeData>();
    [SerializeField] private Transform listContainer;
    [SerializeField] private UpgradeRowUI rowPrefab;

    [Header("Detalhe (painel central)")]
    [SerializeField] private GameObject detailRoot;
    [SerializeField] private Image detailIcon;
    [SerializeField] private TMP_Text detailNameText;
    [SerializeField] private TMP_Text detailDescriptionText;
    [SerializeField] private TMP_Text detailStatusText;
    [SerializeField] private string statusActiveText   = "ACTIVO";
    [SerializeField] private string statusInactiveText = "INACTIVO";
    [SerializeField] private string statusPermanentText = "SEMPRE ACTIVO";
    [SerializeField] private string actionHintToggle   = "A — Ligar / Desligar";
    [SerializeField] private TMP_Text actionHintText;
    [SerializeField] private Color activeColor   = new Color(0.4f, 1f, 0.5f, 1f);
    [SerializeField] private Color inactiveColor = new Color(1f, 0.4f, 0.4f, 1f);
    [SerializeField] private Color permanentColor = new Color(0.7f, 0.7f, 0.7f, 1f);

    [Header("Sons")]
    [SerializeField] private AudioClip toggleOnSfx;
    [SerializeField] private AudioClip toggleOffSfx;

    [Header("Estado Vazio")]
    [SerializeField] private GameObject emptyState;

    private readonly List<GameObject> spawnedRows = new List<GameObject>();
    private UpgradeData selectedUpgrade;

    // ---- ISecondaryMenuTab ----

    public string TabName => "UPGRADES";
    public GameObject Root => root != null ? root : gameObject;

    public void Refresh()
    {
        ClearRows();

        var progress = PlayerProgress.Instance;
        UpgradeRowUI firstRow = null;
        UpgradeData firstUpgrade = null;

        foreach (var upgrade in allUpgrades)
        {
            if (upgrade == null) continue;
            if (progress == null || !progress.HasUpgrade(upgrade)) continue;

            bool enabled = progress.IsUpgradeEnabled(upgrade);

            var row = Instantiate(rowPrefab, listContainer);
            row.gameObject.SetActive(true);
            row.Setup(upgrade, enabled, OnRowSelected, OnRowToggled);

            spawnedRows.Add(row.gameObject);

            if (firstRow == null)
            {
                firstRow = row;
                firstUpgrade = upgrade;
            }
        }

        bool any = spawnedRows.Count > 0;
        if (emptyState != null) emptyState.SetActive(!any);

        if (firstUpgrade != null)
        {
            ShowDetail(firstUpgrade);
            if (EventSystem.current != null && firstRow != null)
                EventSystem.current.SetSelectedGameObject(firstRow.gameObject);
        }
        else if (detailRoot != null)
        {
            detailRoot.SetActive(false);
        }
    }

    public void OnHide()
    {
        // Sem estado local — Refresh() reconstrói na próxima abertura.
    }

    // ---- Detalhes ----

    private void ShowDetail(UpgradeData upgrade)
    {
        if (upgrade == null) return;
        selectedUpgrade = upgrade;

        if (detailRoot != null) detailRoot.SetActive(true);

        if (detailIcon != null)
        {
            detailIcon.sprite = upgrade.icon;
            detailIcon.enabled = upgrade.icon != null;
        }

        if (detailNameText != null) detailNameText.text = upgrade.displayName;
        if (detailDescriptionText != null) detailDescriptionText.text = upgrade.description;

        RefreshDetailStatus(upgrade);
    }

    private void RefreshDetailStatus(UpgradeData upgrade)
    {
        if (upgrade == null) return;

        var progress = PlayerProgress.Instance;

        if (!upgrade.toggleable)
        {
            if (detailStatusText != null)
            {
                detailStatusText.text = statusPermanentText;
                detailStatusText.color = permanentColor;
            }
            if (actionHintText != null) actionHintText.text = string.Empty;
        }
        else
        {
            bool enabled = progress != null && progress.IsUpgradeEnabled(upgrade);
            if (detailStatusText != null)
            {
                detailStatusText.text = enabled ? statusActiveText : statusInactiveText;
                detailStatusText.color = enabled ? activeColor : inactiveColor;
            }
            if (actionHintText != null) actionHintText.text = actionHintToggle;
        }
    }

    // ---- Callbacks das linhas ----

    private void OnRowSelected(UpgradeData upgrade)
    {
        ShowDetail(upgrade);
    }

    private void OnRowToggled(UpgradeData upgrade)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || upgrade == null || !upgrade.toggleable) return;

        bool newValue = !progress.IsUpgradeEnabled(upgrade);
        progress.SetUpgradeEnabled(upgrade, newValue);

        var sfx = newValue ? toggleOnSfx : toggleOffSfx;
        SecondaryMenuController.Instance?.PlaySfx(sfx);

        // Actualiza o indicador visual da linha correspondente.
        foreach (var go in spawnedRows)
        {
            if (go == null) continue;
            var row = go.GetComponent<UpgradeRowUI>();
            if (row != null && row.Upgrade == upgrade)
            {
                row.SetEnabled(newValue);
                break;
            }
        }

        // Actualiza o painel de detalhe se o toggle foi no upgrade actualmente seleccionado.
        if (selectedUpgrade == upgrade) RefreshDetailStatus(upgrade);
    }

    // ---- Limpeza ----

    private void ClearRows()
    {
        foreach (var go in spawnedRows)
            if (go != null) Destroy(go);
        spawnedRows.Clear();
        selectedUpgrade = null;
    }
}

/// <summary>
/// Linha de um upgrade na lista de <see cref="UpgradesTabUI"/>.
/// Mostra ícone, nome e um indicador de estado (activo/inactivo/permanente).
/// Upgrades não-toggleable têm o botão desactivado (não interactivo).
/// </summary>
public class UpgradeRowUI : MonoBehaviour, ISelectHandler
{
    [SerializeField] private Image iconImage;
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private Image toggleIndicator;
    [SerializeField] private Sprite indicatorOnSprite;
    [SerializeField] private Sprite indicatorOffSprite;

    private UpgradeData upgrade;
    private Action<UpgradeData> onSelected;
    private Action<UpgradeData> onToggle;

    public UpgradeData Upgrade => upgrade;

    public void Setup(UpgradeData upgrade, bool enabled, Action<UpgradeData> onSelected, Action<UpgradeData> onToggle)
    {
        this.upgrade    = upgrade;
        this.onSelected = onSelected;
        this.onToggle   = onToggle;

        if (nameText != null) nameText.text = upgrade.displayName;

        if (iconImage != null)
        {
            iconImage.sprite = upgrade.icon;
            iconImage.enabled = upgrade.icon != null;
        }

        SetEnabled(upgrade.toggleable ? enabled : true);

        var button = GetComponent<Button>();
        if (button != null)
        {
            button.interactable = upgrade.toggleable;
            button.onClick.RemoveAllListeners();
            if (upgrade.toggleable)
                button.onClick.AddListener(() => this.onToggle?.Invoke(this.upgrade));
        }
    }

    /// <summary>Actualiza o sprite do indicador sem recriar a linha.</summary>
    public void SetEnabled(bool enabled)
    {
        if (toggleIndicator == null) return;
        toggleIndicator.sprite = enabled ? indicatorOnSprite : indicatorOffSprite;
        toggleIndicator.enabled = toggleIndicator.sprite != null;
    }

    public void OnSelect(BaseEventData eventData)
    {
        onSelected?.Invoke(upgrade);
    }
}
